var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"於是你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"왜 그렇게 빤히 보시죠? 마치 제가 기뻐하는 표정을 짓길 기다리고 있다는 듯이?","JPN":"何をじっと見ているんですか？まるで、私の喜ぶ反応を待っていたかのようですね。","ENG":"Why are you staring at me like that? Are you expecting me to look excited?","TWN":"幹嘛那樣盯著我看？就好像在等我露出高興的表情似的？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"물론 다른 직원에게 이런 제안을 했다면 누구라도 고맙다며 받아들이겠죠.","JPN":"もちろん、他の社員はこのような提案をされたら、誰でもありがたく受け入れるでしょう。","ENG":"Of course, any other employee would accept an offer like this very gratefully.","TWN":"當然，如果您向其他員工提出這樣的提議，不管是誰應該都會心存感激地接受吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"하지만 전 이 바닥에서 꽤 오랫동안 책임자 노릇을 해오다 보니, 거래나 계약이라면 이젠 이골이 나서요.","JPN":"しかし私は、この業界で責任ある立場として長くいたおかげで、取引や契約には慣れています。","ENG":"But having served as a supervisor in this line of work for so long, I don't easily get impressed by deals or contracts.","TWN":"不過我以負責人的身份，在這個圈子做了這麼久，交易和契約什麼的，我都已經習慣了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"게다가 계약이란 건 돈과 신용으로 하는 거잖아요?","JPN":"それに契約というのは、お金と信用があって成り立つものじゃないですか。","ENG":"After all, contracts are based on money and credibility, right?","TWN":"況且，契約這種東西，是要靠錢或信用履行的吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"어차피 우린 돈과 신용을 떠나서 결국 서로를 믿을 수 밖에 없는 입장이니까.","JPN":"結局、私たちはお金や信用とは関係なく、お互い信じなければならない立場ですし。","ENG":"But you and I... we have no choice but to trust each other, regardless of money or credibility.","TWN":"反正拋開錢和信用，我們最終也是不得不信任彼此的關係。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"하긴, 회사엔 보는 눈도 많으니 이런 식으로 구색을 맞춰둔다고 해서 나쁠 건 없겠죠.","JPN":"確かに会社では人目も多いですから、このように形式を整えておくのは悪いことではないと思います。","ENG":"Then again, I guess a little formality like this won't hurt given how many people are watching us at this company.","TWN":"算了，公司裡這麼多隻眼睛在看，用這種方式統一處理也無傷大雅。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"흐음......","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"그래도 지금껏 당연하다는 듯 부리시더니, 의외로 제가 필요하다는 표현도 할 줄 아셨네요.","JPN":"しかし今まで当たり前のように人を使っておいて、君が必要だなんてことも言えるとは意外ですね。","ENG":"Still, I'm impressed you thought of expressing your need for me. You did always take me for granted more or less.","TWN":"雖然您之前一直擺出一副理所當然的樣子，但沒想到您會做出這種''需要我''的表現呢。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"달랑 계약서 한 장 내밀고 반응을 지켜보는 방식의 표현은 정말 별로라고 생각하지만, 이번 한 번은 그냥 넘어가도록 하죠.","JPN":"こんな契約書を1枚出して、反応を探るような方法はとても残念ですが、今回だけは許しましょう。","ENG":"You really could do better than just shoving a piece of paper in my face to see how I'd react, but I'll let it slide this time.","TWN":"只拿出一份契約書觀察反應的方式真的很糟，但這次我就不追究了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"다음에 이런 용무로 호출을 하실 땐 좀 더 괜찮은 아이디어를 준비하시길 바래요.","JPN":"次回、こういったご用で人を呼び出す時は、もっと良いアイディアを準備しておいてください。","ENG":"I hope you'll get a little more creative the next time you decide to call me up for something like this.","TWN":"下次再因為這種事叫我過來時，希望您能準備一個更好的點子。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"자, 이만 얼른 끝내고 다른 업무로 넘어가볼까요?","JPN":"さあ、この話は終わりにして、さっそく次の業務に移りましょう。","ENG":"Alright, that's enough of that. Shall we move on to our next agenda?","TWN":"好了，趕快結束這件事，進行其他工作吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};